import 'package:flutter/material.dart';
import 'dart:async';
import 'package:firebase_core/firebase_core.dart';
import 'package:intl/date_symbol_data_local.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter/services.dart';
import 'package:firebase_auth/firebase_auth.dart';

import 'services/background_handlers.dart';
import 'services/firebase_bootstrap.dart';
import 'services/group_lifecycle_service.dart';
import 'services/session_store.dart';
import 'screens/login_screen.dart';
import 'screens/biometric_quick_auth_screen.dart';
import 'screens/auth_screen.dart';

final ValueNotifier<ThemeMode> themeNotifier = ValueNotifier(ThemeMode.light);


const audioChannel = MethodChannel('com.example.agenda_app/audio');

void main() async {
  WidgetsFlutterBinding.ensureInitialized();

  // Intentar detener cualquier sonido de alarma al arrancar la app
  try {
    await audioChannel.invokeMethod('stopAudio');
  } catch (e) {
    debugPrint('No se pudo detener audio al iniciar: $e');
  }

  final ok = await ensureFirebaseInitialized(logContext: 'arranque');
  if (!ok) {
    debugPrint('Firebase no pudo inicializarse en arranque, se reintentará en login.');
  }

  await initializeDateFormatting('es_ES', null);
  runApp(const AppLoader());
}

class AppLoader extends StatefulWidget {
  const AppLoader({super.key});
  @override
  State<AppLoader> createState() => _AppLoaderState();
}

class _AppLoaderState extends State<AppLoader> {
  bool _initializing = true;
  Widget? _home;

  @override
  void initState() {
    super.initState();
    _initApp();
  }

  Future<void> _initApp() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      themeNotifier.value = (prefs.getBool('darkMode') ?? false) ? ThemeMode.dark : ThemeMode.light;
      await SessionStore.migrateLegacySessionIfNeeded();
      final activeSession = await SessionStore.getActiveSession();
      final firebaseReady = Firebase.apps.isNotEmpty;

      if (firebaseReady) {
        unawaited(GroupLifecycleService.runInactivityLifecycleSweep());
      }

      // Si el usuario está autenticado, entra directo a la app; si no, muestra AuthScreen
      final user = FirebaseAuth.instance.currentUser;
      if (firebaseReady && user != null) {
        _home = BiometricQuickAuthScreen(
          agendaId: activeSession?.agendaId ?? '',
          agendaNombre: activeSession?.agendaNombre ?? '',
          usuario: activeSession?.usuario ?? '',
          rol: activeSession?.rol ?? '',
          modoAcceso: activeSession?.modoAcceso ?? '',
        );
      } else {
        _home = AuthScreen(onLoginSuccess: () => setState(() => _home = null));
      }

      unawaited(_initOptionalServices());
    } catch (e) {
      debugPrint('Error inicialización: $e');
      _home = AuthScreen();
    } finally {
      if (mounted) setState(() => _initializing = false);
    }
  }

  Future<void> _initOptionalServices() async {
    // Servicios opcionales eliminados: alarmas, notificaciones, timezone, permisos
  }

  // Eliminado: _initTimezone()

  // Eliminado: _initNotifications()

  @override
  Widget build(BuildContext context) {
    return ValueListenableBuilder<ThemeMode>(
      valueListenable: themeNotifier,
      builder: (_, mode, __) => MaterialApp(
        debugShowCheckedModeBanner: false,
        themeMode: mode,
        theme: ThemeData.light(),
        darkTheme: ThemeData.dark(),
        home: _initializing 
          ? const Scaffold(body: Center(child: CircularProgressIndicator())) 
          : (_home ?? const LoginScreen()),
      ),
    );
  }
}
